function solve(nums) {
    let totalSumX = 0;
    const n = nums.length;

    // We need nums[i] <= nums[i+1] for all i.
    // If nums[i] > nums[i+1], we must increase nums[i+1] (and potentially subsequent elements)
    // relative to nums[i] by at least nums[i] - nums[i+1].

    // The key insight is to look at the required increase at each adjacent pair.
    // If nums[i] > nums[i+1], we need to increase nums[i+1] by at least diff = nums[i] - nums[i+1].
    // This required increase must be achieved by applying operations that cover index i+1.

    // Consider the difference d[i] = nums[i] - nums[i+1].
    // If d[i] > 0, we need an increase of at least d[i] on nums[i+1] relative to nums[i].

    // Let the final array be nums'. We require nums'[i] <= nums'[i+1].
    // Let x_j be the amount added by the j-th operation.
    // The total increase on nums[i] is sum(x_j for all ops covering i).

    // The minimum total sum of x's is achieved when we only add the necessary minimum amount at each point of decrease.

    // If nums[i] > nums[i+1], we must increase nums[i+1] by at least nums[i] - nums[i+1] more than nums[i].
    // Since we are adding x to a *subarray*, an operation covering [l, r] adds x to both nums[i] and nums[i+1] if l <= i < i+1 <= r.
    // If we only care about the relationship between adjacent elements, we only need to focus on fixing the violations.

    // If nums[i] > nums[i+1], let diff = nums[i] - nums[i+1].
    // We need to ensure that the total amount added to nums[i+1] is at least 'diff' more than the total amount added to nums[i].
    // An operation on [l, r] contributes equally to both if l <= i and r >= i+1.
    // The only way to increase nums[i+1] relative to nums[i] is to apply an operation that covers i+1 but *not* i, or covers i+1 with a larger x than the operation covering i (which is impossible since x is fixed per operation).

    // Wait, the problem states: "you can choose any subarray nums[l..r], and increase EACH element by x".
    // If we increase [i+1, r] by x, nums[i] is unchanged, and nums[i+1] increases by x. This fixes the gap.
    // If we increase [l, i] by x, nums[i+1] is unchanged, and nums[i] increases by x. This makes the gap worse or keeps it the same (if we increase both).

    // To fix nums[i] > nums[i+1] by an amount diff = nums[i] - nums[i+1]:
    // We must apply an operation with value 'diff' on a subarray starting at i+1 (i.e., [i+1, r] where r >= i+1).
    // This operation increases nums[i+1] by 'diff' but leaves nums[i] unchanged.
    // This contributes 'diff' to the total sum of x's.

    // Since these required increases are independent for each violation, the minimum total sum of x's is the sum of all required differences.

    for (let i = 0; i < n - 1; i++) {
        if (nums[i] > nums[i+1]) {
            const diff = nums[i] - nums[i+1];
            totalSumX += diff;
        }
    }

    return totalSumX;
}

